mapper.select:
		/*
             SQL ID : ExamStareHstyDAO.selectStareHsty
            	 설  명 : 시험 참여 이력 코드 조회
         */
         SELECT * FROM (
         SELECT
         	STARE_HSTY_SN
           FROM TB_LMS_EXAM_STARE_HSTY
          WHERE EXAM_ID = #{examCd}
            AND STD_ID = #{stdNo}
          ORDER BY FRST_INQ_DTTM DESC
          )
          WHERE ROWNUM = 1

mapper.delete:
	/*
   		SQL ID : ExamStareHstyDAO.deleteAllStareHsty
       	설  명 : 시험 응시 이력 전체 삭제
     */
     DELETE FROM TB_LMS_EXAM_STARE_HSTY
      WHERE EXAM_ID = #{examCd}
